import{_ as o,o as a,c,a2 as d}from"./chunks/framework.IwO0Hdn_.js";const m=JSON.parse('{"title":"[DATA] F-00.2 — Migraciones y Modelos Eloquent","description":"","frontmatter":{},"headers":[],"relativePath":"backlog/F-00.2_migraciones_modelos.md","filePath":"backlog/F-00.2_migraciones_modelos.md","lastUpdated":null}'),r={name:"backlog/F-00.2_migraciones_modelos.md"};function s(t,e,i,n,l,g){return a(),c("div",null,[...e[0]||(e[0]=[d('<h1 id="data-f-00-2-—-migraciones-y-modelos-eloquent" tabindex="-1">[DATA] F-00.2 — Migraciones y Modelos Eloquent <a class="header-anchor" href="#data-f-00-2-—-migraciones-y-modelos-eloquent" aria-label="Permalink to &quot;[DATA] F-00.2 — Migraciones y Modelos Eloquent&quot;">​</a></h1><p><strong>Épica:</strong> EPIC-00 — Setup e Infraestructura Base</p><h2 id="🏷️-categoria" tabindex="-1">🏷️ Categoría <a class="header-anchor" href="#🏷️-categoria" aria-label="Permalink to &quot;🏷️ Categoría&quot;">​</a></h2><p><strong>Categoría:</strong> <code>Data</code><strong>Impacta en:</strong> Equipo Backend (Laravel + Base de Datos)</p><h2 id="📦-dependencias" tabindex="-1">📦 Dependencias <a class="header-anchor" href="#📦-dependencias" aria-label="Permalink to &quot;📦 Dependencias&quot;">​</a></h2><blockquote><p>Backlogs que deben estar <strong>completados</strong> antes de implementar esta feature.</p></blockquote><table tabindex="0"><thead><tr><th>Backlog</th><th>Motivo</th></tr></thead><tbody><tr><td><a href="./F-00.1_setup_laravel_livewire.html">F-00.1</a></td><td>Base Laravel + Livewire instalada, <code>artisan</code> y Composer disponibles</td></tr></tbody></table><p><strong>Prioridad:</strong> <code>Must</code></p><hr><p><strong>Descripción:</strong> Como desarrollador Quiero que todas las tablas del panel estén creadas con migraciones Laravel y que los modelos Eloquent tengan sus relaciones definidas Para que el equipo pueda trabajar con el ORM de forma segura y consistente desde el principio</p><p><strong>Criterios de Aceptación (Checklist):</strong></p><ul><li>[ ] <strong>Escenario 1 (Migración users):</strong> Tabla <code>users</code> con campos: <code>id (bigserial PK)</code>, <code>name (varchar)</code>, <code>email (varchar unique)</code>, <code>external_id (varchar nullable)</code>, <code>timestamps</code>.</li><li>[ ] <strong>Escenario 2 (Tabla logs — solo lectura):</strong> La tabla <code>logs</code> existe en la BD desde n8n. La migración del panel la documenta como referencia pero <strong>no la crea si ya existe</strong> (migración condicional o documentación en <code>0_descripcion_proyecto.md</code>). Campos esperados: <code>id</code>, <code>type</code>, <code>app_source</code>, <code>message</code>, <code>metadata (jsonb)</code>, <code>archived (boolean default false)</code>, <code>created_at</code>.</li><li>[ ] <strong>Escenario 3 (Migración archived_logs):</strong> Tabla <code>archived_logs</code> con campos: <code>id (bigserial PK)</code>, <code>original_log_id (bigint nullable)</code>, <code>archived_by_id (bigint FK → users.id)</code>, <code>type (varchar)</code>, <code>app_source (varchar)</code>, <code>message (text)</code>, <code>metadata (jsonb nullable)</code>, <code>description (text nullable)</code>, <code>url_tutorial (varchar 500 nullable)</code>, <code>archived_at (timestamptz)</code>, <code>timestamps</code>.</li><li>[ ] <strong>Escenario 4 (Migración comments):</strong> Tabla <code>comments</code> con campos: <code>id</code>, <code>archived_log_id (bigint FK → archived_logs.id CASCADE DELETE)</code>, <code>user_id (bigint FK → users.id)</code>, <code>content (text)</code>, <code>timestamps</code>.</li><li>[ ] <strong>Escenario 5 (Migración error_codes):</strong> Tabla <code>error_codes</code> con campos: <code>id (bigserial PK)</code>, <code>code (varchar)</code>, <code>app_source (varchar)</code>, <code>name (varchar)</code>, <code>description (text nullable)</code>, <code>file (varchar nullable)</code>, <code>line (integer nullable)</code>, <code>timestamps</code>. Unique constraint: <code>(code, app_source)</code>.</li><li>[ ] <strong>Escenario 6 (Migración error_code_comments):</strong> Tabla <code>error_code_comments</code> con campos: <code>id</code>, <code>error_code_id (bigint FK → error_codes.id CASCADE DELETE)</code>, <code>user_id (bigint FK → users.id)</code>, <code>content (text)</code>, <code>timestamps</code>.</li><li>[ ] <strong>Escenario 7 (Modelos Eloquent):</strong> Modelos <code>User</code>, <code>Log</code>, <code>ArchivedLog</code>, <code>Comment</code>, <code>ErrorCode</code>, <code>ErrorCodeComment</code> con relaciones <code>hasMany</code>/<code>belongsTo</code> correctas. <code>Log</code> es de solo lectura (sin <code>$fillable</code> de escritura en el panel).</li><li>[ ] <strong>Requisito Técnico:</strong> Todas las migraciones en <code>database/migrations/</code>. Índices en columnas de filtro: <code>logs(type)</code>, <code>logs(app_source)</code>, <code>logs(archived)</code>, <code>logs(created_at)</code>, <code>archived_logs(type)</code>, <code>archived_logs(archived_at)</code>. <code>php artisan migrate:fresh --seed</code> debe correr sin errores.</li></ul><hr><p><strong>MoSCoW:</strong> <code>MUST</code><strong>Sprint:</strong> Sprint 0</p><p><strong>Notas:</strong></p><ul><li>La tabla <code>logs</code> puede ya existir en el servidor de producción. La migración del panel debe contemplar esto (usar <code>Schema::hasTable(&#39;logs&#39;)</code> o gestionar manualmente).</li><li>Los índices compuestos son críticos para el rendimiento dado el volumen de logs esperado (NFR-ESC-02).</li></ul>',16)])])}const u=o(r,[["render",s]]);export{m as __pageData,u as default};
